select v_1 as "o_orderkey", v_2 as "o_orderdate", v_3 as "txt" from (select v_1, v_2, (v_4 || ' comment: ') || v_5 as v_3 from (select * from (select "o_orderkey" as v_1, "o_orderstatus" as v_4, "o_orderdate" as v_2, "o_comment" as v_5 from "orders") s where v_2 < (date('1995-03-15', '+10 days'))) s) s order by v_2 desc limit 10
